async (params, browser) => {
  // Open Discord channel
  await browser.open(`${params.channel_url}`)

  // Wait for channel to load
  await browser.waitForSelector('div[role=\'textbox\']', 15000)

  await browser.wait(2000)

  // Show member list
  const show_members = await browser.evaluate(`const membersToggle = document.querySelector('button[aria-label*="Member"], button[aria-label*="member"]'); if (membersToggle) membersToggle.click(); return { toggled: true }`)

  await browser.wait(2000)

  // Extract member list
  const members_list = await browser.evaluate(`const members = []; const memberList = document.querySelector('[aria-label="Members"]') || document.querySelector('aside div[data-list-id="members"]'); if (!memberList) { return { member_count: 0, members: [], error: 'Member list not found. It may be hidden or you may need to toggle it.' }; } let currentRole = ''; const items = memberList.querySelectorAll('[data-list-item-id]'); for (const el of items) { const itemId = el.getAttribute('data-list-item-id') || ''; if (itemId.startsWith('members-')) { const roleText = el.querySelector('h2, h3, span'); if (roleText) { currentRole = roleText.textContent.trim().replace(/\s*-\s*\d+$/, '').replace(/\s*\d+$/, ''); continue; } } const nameEl = el.querySelector('[class*="username"] span, [class*="name"] span, span[class*="roleColor"]'); if (!nameEl) { const innerSpans = el.querySelectorAll('span'); for (const s of innerSpans) { if (s.textContent.trim() && s.textContent.trim().length < 50 && !s.querySelector('span')) { members.push({ username: s.textContent.trim(), role: currentRole, status: '' }); break; } } continue; } const statusEl = el.querySelector('[aria-label*="status"], [class*="status"]'); members.push({ username: nameEl.textContent.trim(), role: currentRole, status: statusEl ? statusEl.getAttribute('aria-label') || statusEl.textContent.trim() : '' }); } return { member_count: members.length, members: members.slice(0, 50) }`)

  return members_list
}
